-- Get user and organization info
SET @user_id = (SELECT id FROM users WHERE email LIKE '%deji%' OR name LIKE '%deji%' LIMIT 1);
SET @org_id = (SELECT organization_id FROM users WHERE id = @user_id LIMIT 1);

-- Insert test project
INSERT INTO projects (name, code, organization_id, totalBudget, spentBudget, status, createdAt, updatedAt)
VALUES ('Test Invoice Project', 'TEST-INV-002', @org_id, 10000.00, 0.00, 'active', NOW(), NOW())
ON DUPLICATE KEY UPDATE name = name;

SET @project_id = (SELECT id FROM projects WHERE code = 'TEST-INV-002' LIMIT 1);

-- Insert completed session
INSERT INTO sessions (
  projectId, title, description, startTime, endTime, venue, status,
  paymentPerFacilitator, isVirtual, createdById, organizationId, createdAt, updatedAt
) VALUES (
  @project_id, 'Test Session for Invoice', 'Test session to verify invoice generation',
  DATE_SUB(NOW(), INTERVAL 1 DAY), DATE_SUB(NOW(), INTERVAL 1 DAY) + INTERVAL 1 HOUR,
  'Test Venue', 'completed', 75.00, 0, @user_id, @org_id, NOW(), NOW()
);

SET @session_id = LAST_INSERT_ID();

-- Add facilitator
INSERT INTO session_facilitators (sessionId, userId, createdAt)
VALUES (@session_id, @user_id, NOW());

-- Record attendance
INSERT INTO attendance (
  sessionId, userId, joinedAt, leftAt, durationMinutes, wasLate,
  calculatedPayment, organizationId, createdAt, updatedAt
) VALUES (
  @session_id, @user_id, DATE_SUB(NOW(), INTERVAL 1 DAY),
  DATE_SUB(NOW(), INTERVAL 1 DAY) + INTERVAL 1 HOUR,
  60, 0, '75.00', @org_id, NOW(), NOW()
);

-- Verify
SELECT s.id, s.title, s.status, s.paymentPerFacilitator, a.calculatedPayment, u.name
FROM sessions s
JOIN attendance a ON s.id = a.sessionId
JOIN users u ON a.userId = u.id
WHERE s.id = @session_id;

